import React, { useState, useEffect, useCallback } from 'react';
import { useSearchParams } from 'react-router-dom';
import { productAPI } from '../services/api';
import ProductCard from '../components/products/ProductCard';
import ProductFilters from '../components/products/ProductFilters';
import Pagination from '../components/ui/Pagination';
import SortIcon from '@mui/icons-material/Sort';
import TuneIcon from '@mui/icons-material/Tune';

const SORT_OPTIONS = [
  { value: 'newest', label: 'Newest First' },
  { value: 'price-asc', label: 'Price: Low to High' },
  { value: 'price-desc', label: 'Price: High to Low' },
  { value: 'rating-desc', label: 'Top Rated' },
  { value: 'popular', label: 'Most Popular' },
];

const ShopPage = () => {
  const [searchParams, setSearchParams] = useSearchParams();
  const [products, setProducts] = useState([]);
  const [pagination, setPagination] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showMobileFilters, setShowMobileFilters] = useState(false);

  // All filter state derived from URL params — backend handles everything
  const filters = {
    page: searchParams.get('page') || 1,
    limit: 12,
    category: searchParams.get('category') || '',
    minPrice: searchParams.get('minPrice') || '',
    maxPrice: searchParams.get('maxPrice') || '',
    rating: searchParams.get('rating') || '',
    flavor: searchParams.get('flavor') || '',
    sort: searchParams.get('sort') || 'newest',
    search: searchParams.get('search') || '',
    featured: searchParams.get('featured') || '',
    caffeineLevel: searchParams.get('caffeineLevel') || '',
  };

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    // Send all filter/pagination params to backend — no client-side filtering
    const params = Object.fromEntries(Object.entries(filters).filter(([, v]) => v !== '' && v !== undefined));
    try {
      const { data } = await productAPI.getAll(params);
      setProducts(data.data);
      setPagination(data.pagination);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [searchParams]); // eslint-disable-line

  useEffect(() => { fetchProducts(); }, [fetchProducts]);

  const handleFilterChange = (newFilters) => {
    const params = {};
    Object.entries(newFilters).forEach(([k, v]) => { if (v !== '' && v != null) params[k] = v; });
    setSearchParams(params);
  };

  const handlePageChange = (page) => handleFilterChange({ ...filters, page });

  const handleClearFilters = () => {
    setSearchParams({ sort: filters.sort });
  };

  const handleSortChange = (e) => handleFilterChange({ ...filters, sort: e.target.value, page: 1 });

  const handleSearch = (e) => {
    if (e.key === 'Enter') handleFilterChange({ ...filters, search: e.target.value, page: 1 });
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
        <div>
          <h1 className="font-display text-3xl text-tea-900">
            {filters.category ? filters.category.replace('-', ' ').replace(/\b\w/g, (c) => c.toUpperCase()) : 'All Teas'}
          </h1>
          {pagination && (
            <p className="text-gray-500 text-sm mt-1">{pagination.total} products found</p>
          )}
        </div>
        <div className="flex items-center gap-3 w-full sm:w-auto">
          {/* Search */}
          <input
            type="text"
            placeholder="Search teas..."
            defaultValue={filters.search}
            onKeyDown={handleSearch}
            className="input flex-1 sm:w-52"
          />
          {/* Sort */}
          <div className="flex items-center gap-2 border border-gray-200 rounded-lg px-3 py-2">
            <SortIcon fontSize="small" className="text-gray-400" />
            <select value={filters.sort} onChange={handleSortChange} className="text-sm bg-transparent focus:outline-none text-gray-700">
              {SORT_OPTIONS.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
            </select>
          </div>
          {/* Mobile filter toggle */}
          <button onClick={() => setShowMobileFilters(true)} className="lg:hidden p-2 border border-gray-200 rounded-lg">
            <TuneIcon fontSize="small" />
          </button>
        </div>
      </div>

      <div className="flex gap-8">
        {/* Desktop Filters */}
        <div className="hidden lg:block">
          <ProductFilters filters={filters} onChange={handleFilterChange} onClear={handleClearFilters} />
        </div>

        {/* Mobile Filters Drawer */}
        {showMobileFilters && (
          <div className="fixed inset-0 z-50 flex">
            <div className="fixed inset-0 bg-black/40" onClick={() => setShowMobileFilters(false)} />
            <div className="relative ml-auto w-72 h-full bg-cream overflow-y-auto p-4">
              <ProductFilters filters={filters} onChange={(f) => { handleFilterChange(f); setShowMobileFilters(false); }} onClear={handleClearFilters} />
            </div>
          </div>
        )}

        {/* Products Grid */}
        <div className="flex-1 min-w-0">
          {loading ? (
            <div className="grid grid-cols-2 xl:grid-cols-3 gap-5">
              {[...Array(12)].map((_, i) => (
                <div key={i} className="card animate-pulse">
                  <div className="aspect-square bg-tea-100" />
                  <div className="p-4 space-y-2">
                    <div className="h-3 bg-tea-100 rounded w-1/3" />
                    <div className="h-4 bg-tea-100 rounded w-3/4" />
                    <div className="h-3 bg-tea-100 rounded w-1/2" />
                    <div className="h-4 bg-tea-100 rounded w-1/4 mt-2" />
                  </div>
                </div>
              ))}
            </div>
          ) : products.length === 0 ? (
            <div className="text-center py-20">
              <p className="text-5xl mb-4">🍵</p>
              <h3 className="font-display text-xl text-tea-900 mb-2">No teas found</h3>
              <p className="text-gray-500 text-sm mb-6">Try adjusting your filters or search terms.</p>
              <button onClick={handleClearFilters} className="btn-secondary">Clear Filters</button>
            </div>
          ) : (
            <>
              <div className="grid grid-cols-2 xl:grid-cols-3 gap-5">
                {products.map((product) => <ProductCard key={product._id} product={product} />)}
              </div>
              <Pagination pagination={pagination} onPageChange={handlePageChange} />
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default ShopPage;
